const store = $getWorkflowStaticData('global');

if (!store.seen) store.seen = {};

const now = Date.now();
const ttl = 15 * 60 * 1000; // 15 min

for (const k in store.seen) {
  if (now - store.seen[k] > ttl) delete store.seen[k];
}

const raw = String($json.extracted_text || '')
  .toLowerCase()
  .trim()
  .replace(/\s+/g, ' ')
  .replace(/[^a-z0-9\u00C0-\u024F\u0400-\u04FF\s@+.-]/gi, '');

if (!raw) return []; // skip empty

let hash = 0;
for (let i = 0; i < raw.length; i++) {
  hash = ((hash << 5) - hash) + raw.charCodeAt(i);
  hash |= 0;
}

const key = String(hash);

if (store.seen[key]) {
  return []; // 🔥 STOP HERE if duplicate
}

store.seen[key] = now;

return items; // ✅ Only return items if not duplicate

const text = ($json.extracted_text || '').toLowerCase().trim();

const normalized = text
  .replace(/\s+/g, ' ')
  .replace(/[^a-z0-9\u00C0-\u024F\u0400-\u04FF\s@+.-]/gi, '');

// 🌍 KEYWORDS MULTIIDIOMA (ES / EN / RU / PT-BR)
const mustPassKeywords = [
  'plaza', 'habitacion', 'vacante', 'alojamiento', 'alquiler', // ES
  'spot', 'room', 'vacancy', 'accommodation', 'rent', // EN
  'vaga', 'quarto', 'alojamento', 'aluguel', // PT-BR
  'место', 'комната', 'вакансия', 'жилье', 'аренда' // RU
];

const contextKeywords = [
  'chica', 'modelo', 'mujer', 'cliente', 'presencia', 'vip', 'hotel', 'cena', 'viaje', 'acuerdo', 'cita', 'budget', 'profesional', 'joven', 'natural', 'tatuaje', // ES
  'girl', 'model', 'woman', 'client', 'presence', 'vip', 'hotel', 'dinner', 'travel', 'deal', 'date', 'budget', 'professional', 'young', 'natural', 'tattoo', // EN
  'garota', 'modelo', 'mulher', 'cliente', 'presença', 'vip', 'hotel', 'jantar', 'viagem', 'acordo', 'encontro', 'budget', 'profissional', 'jovem', 'natural', 'tatuagem', // PT-BR
  'девушка', 'модель', 'женщина', 'клиент', 'внешность', 'vip', 'отель', 'ужин', 'поездка', 'сделка', 'встреча', 'бюджет', 'профессионал', 'молодая', 'натуральная', 'тату' // RU
];

const hasCore = mustPassKeywords.some(k => normalized.includes(k));
const hasContext = contextKeywords.some(k => normalized.includes(k));

// 🚀 BYPASS TOTAL
if (hasCore && hasContext) {
  return [{
    ...$json,
    looksValuable: true,
    prefilter_score: 999,
    bypass: true
  }];
}

// ⚙️ SCORE ESTANDAR (si no hay bypass)
let score = 0;
if (normalized.length >= 12) score++;
if (normalized.length >= 25) score++;
if (mustPassKeywords.some(s => normalized.includes(s))) score += 3;
if (/\d/.test(normalized)) score++;
if (/@|\+?\d{6,}/.test(normalized)) score += 2;

const looksValuable = score >= 3;

return [{ ...$json, looksValuable, prefilter_score: score, bypass: false }];

let content;
try {
  content = JSON.parse($input.first().json.choices[0].message.content || '{}');
} catch (e) {
  return [{ trash: true }];
}
return [{ ...content }];
